create table dirkspzm32.lvs_fahrzeuge_ls_id (
    sid                    varchar2(2 char) not null enable,
    firma_nr               number(2, 0) not null enable,
    res_id                 number(*, 0) not null enable,
    stapler_ls_id          number(*, 0) not null enable,
    stapler_ls_bezeichnung varchar2(50 char),
    created_date           date not null enable,
    created_login_id       number(*, 0) not null enable,
    last_change_date       date,
    last_change_login_id   number(*, 0),
    stapler_ls_id_enable   varchar2(1 char) default 'T' not null enable
);

alter table dirkspzm32.lvs_fahrzeuge_ls_id
    add constraint pk_lvs_fahrzeug_ls_id primary key ( res_id,
                                                       stapler_ls_id )
        using index enable;


